-- ═══════════════════════════════════════════════════════════════════════════
-- NIFS v5.0 — Supabase Database Schema + Seed Data
-- Nursing Intelligence System (NIS) — Nurse-PaLM Cognitive Architecture
--
-- Database: PostgreSQL 15+ (Supabase compatible)
-- Extensions: uuid-ossp, pgcrypto, pgvector
-- Schemas: ni, ni_clinical, ni_pharm, ni_legis, ni_user, ni_graph,
--          ni_reasoning, ni_memory, ni_world, ni_attention, ni_prob,
--          ni_planner, ni_learning, ni_twin, ni_council, ni_temporal, ni_ai
--
-- Generated: 2026-07-05
-- Owner: Leivis Melo
-- Source: NIFS Specification v5.0 + NKOS 2026 runtime data
-- ═══════════════════════════════════════════════════════════════════════════


-- ═══════════════════════════════════════════════════════════════════════════
-- EXTENSIONS
-- ═══════════════════════════════════════════════════════════════════════════
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE EXTENSION IF NOT EXISTS "pgvector";


-- ═══════════════════════════════════════════════════════════════════════════
-- SCHEMAS
-- ═══════════════════════════════════════════════════════════════════════════
CREATE SCHEMA IF NOT EXISTS ni;
CREATE SCHEMA IF NOT EXISTS ni_clinical;
CREATE SCHEMA IF NOT EXISTS ni_pharm;
CREATE SCHEMA IF NOT EXISTS ni_legis;
CREATE SCHEMA IF NOT EXISTS ni_user;
CREATE SCHEMA IF NOT EXISTS ni_graph;
CREATE SCHEMA IF NOT EXISTS ni_reasoning;
CREATE SCHEMA IF NOT EXISTS ni_memory;
CREATE SCHEMA IF NOT EXISTS ni_world;
CREATE SCHEMA IF NOT EXISTS ni_attention;
CREATE SCHEMA IF NOT EXISTS ni_prob;
CREATE SCHEMA IF NOT EXISTS ni_planner;
CREATE SCHEMA IF NOT EXISTS ni_learning;
CREATE SCHEMA IF NOT EXISTS ni_twin;
CREATE SCHEMA IF NOT EXISTS ni_council;
CREATE SCHEMA IF NOT EXISTS ni_temporal;
CREATE SCHEMA IF NOT EXISTS ni_ai;


-- ═══════════════════════════════════════════════════════════════════════════
-- CORE TABLES (ni schema) — Referenced by cognitive layers via FK
-- ═══════════════════════════════════════════════════════════════════════════

-- Cases (clinical encounters)
CREATE TABLE IF NOT EXISTS ni.cases (
    case_id         UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    patient_identifier VARCHAR(64),
    case_type       VARCHAR(32) DEFAULT 'clinical',
    status          VARCHAR(16) DEFAULT 'open',
    context         JSONB DEFAULT '{}',
    created_date    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_date    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    created_by      VARCHAR(64)
);

-- Populations (patient demographics/profiles)
CREATE TABLE IF NOT EXISTS ni.populations (
    population_code VARCHAR(32) PRIMARY KEY,
    name            VARCHAR(128) NOT NULL,
    description     TEXT,
    created_date    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Care plans
CREATE TABLE IF NOT EXISTS ni.care_plans (
    plan_id         UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    case_id         UUID REFERENCES ni.cases(case_id) ON DELETE CASCADE,
    status          VARCHAR(16) DEFAULT 'draft',
    plan_data       JSONB DEFAULT '{}',
    created_date    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_date    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    created_by      VARCHAR(64)
);


-- ═══════════════════════════════════════════════════════════════════════════
-- NANDA-I DIAGNOSES (ni_clinical schema)
-- ═══════════════════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS ni_clinical.nanda_diagnoses (
    nanda_code              VARCHAR(8) PRIMARY KEY,
    diagnosis_code          VARCHAR(32) NOT NULL UNIQUE,
    name                    VARCHAR(256) NOT NULL,
    name_pt                 VARCHAR(512),
    domain_code             VARCHAR(64),
    class_code              VARCHAR(64),
    definition              TEXT,
    defining_characteristics JSONB DEFAULT '[]',
    related_factors         JSONB DEFAULT '[]',
    taxonomy_code           VARCHAR(32),
    snomed_ct_code          VARCHAR(32),
    icd11_code              VARCHAR(32),
    evidence_code           VARCHAR(32),
    edition                 VARCHAR(8) DEFAULT '2026',
    status                  VARCHAR(16) DEFAULT 'active',
    related_tool_codes      JSONB DEFAULT '[]',
    reference_framework     VARCHAR(64),
    content_source          VARCHAR(32),
    created_date            TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_date            TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_nanda_domain ON ni_clinical.nanda_diagnoses(domain_code);
CREATE INDEX idx_nanda_class ON ni_clinical.nanda_diagnoses(class_code);
CREATE INDEX idx_nanda_status ON ni_clinical.nanda_diagnoses(status);
CREATE INDEX idx_nanda_snomed ON ni_clinical.nanda_diagnoses(snomed_ct_code);


-- ═══════════════════════════════════════════════════════════════════════════
-- NIC INTERVENTIONS (ni_clinical schema)
-- ═══════════════════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS ni_clinical.nic_interventions (
    nic_code        VARCHAR(8) PRIMARY KEY,
    intervention_code VARCHAR(32) NOT NULL UNIQUE,
    name            VARCHAR(256) NOT NULL,
    name_pt         VARCHAR(512),
    domain          VARCHAR(64),
    definition      TEXT,
    activities      JSONB DEFAULT '[]',
    snomed_ct_code  VARCHAR(32),
    related_tool_codes JSONB DEFAULT '[]',
    edition         VARCHAR(8) DEFAULT '2026',
    status          VARCHAR(16) DEFAULT 'active',
    created_date    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_date    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_nic_domain ON ni_clinical.nic_interventions(domain);
CREATE INDEX idx_nic_status ON ni_clinical.nic_interventions(status);


-- ═══════════════════════════════════════════════════════════════════════════
-- NOC OUTCOMES (ni_clinical schema)
-- ═══════════════════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS ni_clinical.noc_outcomes (
    noc_code        VARCHAR(8) PRIMARY KEY,
    outcome_code    VARCHAR(32) NOT NULL UNIQUE,
    name            VARCHAR(256) NOT NULL,
    name_pt         VARCHAR(512),
    domain          VARCHAR(64),
    definition      TEXT,
    indicators      JSONB DEFAULT '[]',
    scale_code      VARCHAR(32),
    edition         VARCHAR(8) DEFAULT '2026',
    status          VARCHAR(16) DEFAULT 'active',
    created_date    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_date    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_noc_domain ON ni_clinical.noc_outcomes(domain);


-- ═══════════════════════════════════════════════════════════════════════════
-- NNN LINKAGES (ni_clinical schema)
-- ═══════════════════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS ni_clinical.nnn_linkages (
    linkage_code    VARCHAR(64) PRIMARY KEY,
    diagnosis_code  VARCHAR(32) NOT NULL,
    intervention_code VARCHAR(32) NOT NULL,
    outcome_code    VARCHAR(32) NOT NULL,
    strength        VARCHAR(16) DEFAULT 'moderate',
    evidence_code   VARCHAR(32),
    status          VARCHAR(16) DEFAULT 'active',
    created_date    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_date    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    
    CONSTRAINT chk_linkage_strength CHECK (strength IN ('strong', 'moderate', 'suggestive'))
);

CREATE INDEX idx_nnn_dx ON ni_clinical.nnn_linkages(diagnosis_code);
CREATE INDEX idx_nnn_int ON ni_clinical.nnn_linkages(intervention_code);
CREATE INDEX idx_nnn_out ON ni_clinical.nnn_linkages(outcome_code);


-- ═══════════════════════════════════════════════════════════════════════════
-- CLINICAL CONCEPTS (ni_clinical schema)
-- ═══════════════════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS ni_clinical.concepts (
    concept_code    VARCHAR(64) PRIMARY KEY,
    name            VARCHAR(256) NOT NULL,
    name_pt         VARCHAR(512),
    taxonomy_code   VARCHAR(32),
    concept_type    VARCHAR(32),
    snomed_ct_code  VARCHAR(32),
    icd11_code      VARCHAR(32),
    parent_code     VARCHAR(64),
    synonyms        JSONB DEFAULT '[]',
    status          VARCHAR(16) DEFAULT 'active',
    created_date    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_date    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_concepts_type ON ni_clinical.concepts(concept_type);
CREATE INDEX idx_concepts_taxonomy ON ni_clinical.concepts(taxonomy_code);
CREATE INDEX idx_concepts_parent ON ni_clinical.concepts(parent_code);
CREATE INDEX idx_concepts_snomed ON ni_clinical.concepts(snomed_ct_code);


-- ═══════════════════════════════════════════════════════════════════════════
-- EVIDENCE (ni_clinical schema)
-- ═══════════════════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS ni_clinical.evidence (
    evidence_code   VARCHAR(32) PRIMARY KEY,
    framework       VARCHAR(32) DEFAULT 'GRADE',
    level           VARCHAR(16) NOT NULL,
    level_label     VARCHAR(64),
    description     TEXT,
    study_types     JSONB DEFAULT '[]',
    recommendation_strength VARCHAR(16),
    created_date    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);


-- ═══════════════════════════════════════════════════════════════════════════
-- CLINICAL GUIDELINES (ni_clinical schema)
-- ═══════════════════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS ni_clinical.guidelines (
    guideline_code  VARCHAR(64) PRIMARY KEY,
    source          VARCHAR(128) NOT NULL,
    title           VARCHAR(512) NOT NULL,
    year            INTEGER,
    ipsg_goal_code  VARCHAR(16),
    evidence_code   VARCHAR(32),
    url             TEXT,
    created_date    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);


-- ═══════════════════════════════════════════════════════════════════════════
-- INSTITUTIONAL PROTOCOLS (ni_clinical schema)
-- ═══════════════════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS ni_clinical.protocols (
    protocol_code       VARCHAR(64) PRIMARY KEY,
    title               VARCHAR(512) NOT NULL,
    source_guideline_code VARCHAR(64),
    related_tool_codes  JSONB DEFAULT '[]',
    status              VARCHAR(16) DEFAULT 'active',
    created_date        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_date        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);


-- ═══════════════════════════════════════════════════════════════════════════
-- CALCULATOR DEFINITIONS (ni_clinical schema)
-- ═══════════════════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS ni_clinical.calculators (
    definition_code VARCHAR(64) PRIMARY KEY,
    tool_code       VARCHAR(64) NOT NULL UNIQUE,
    name            VARCHAR(256) NOT NULL,
    acronym         VARCHAR(32),
    tool_type       VARCHAR(32),
    category        VARCHAR(64),
    domain          VARCHAR(64),
    parameters      JSONB DEFAULT '[]',
    formula         TEXT,
    interpretation_bands JSONB DEFAULT '[]',
    related_nanda   JSONB DEFAULT '[]',
    related_nic     JSONB DEFAULT '[]',
    status          VARCHAR(16) DEFAULT 'active',
    created_date    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_date    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_calc_category ON ni_clinical.calculators(category);
CREATE INDEX idx_calc_domain ON ni_clinical.calculators(domain);


-- ═══════════════════════════════════════════════════════════════════════════
-- PHARMACY (ni_pharm schema)
-- ═══════════════════════════════════════════════════════════════════════════

-- Drug References
CREATE TABLE IF NOT EXISTS ni_pharm.drug_references (
    drug_code           VARCHAR(32) PRIMARY KEY,
    generic_name        VARCHAR(256) NOT NULL,
    generic_name_pt     VARCHAR(256),
    atc_code            VARCHAR(16),
    pharmacological_class VARCHAR(128),
    high_alert          BOOLEAN DEFAULT FALSE,
    routes              JSONB DEFAULT '[]',
    status              VARCHAR(16) DEFAULT 'active',
    created_date        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_date        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_drug_atc ON ni_pharm.drug_references(atc_code);
CREATE INDEX idx_drug_high_alert ON ni_pharm.drug_references(high_alert);

-- Medication Dictionary
CREATE TABLE IF NOT EXISTS ni_pharm.medication_dictionary (
    entity_code         VARCHAR(64) PRIMARY KEY,
    concept_code        VARCHAR(64),
    parent_entity_code  VARCHAR(64),
    parent_entity_type  VARCHAR(32),
    drug_ref_code       VARCHAR(32) REFERENCES ni_pharm.drug_references(drug_code),
    linked_monograph_code VARCHAR(64),
    term_pt             VARCHAR(256),
    slug                VARCHAR(128),
    nursing_definition  TEXT,
    monitoring_pt       TEXT,
    evidence_grade      VARCHAR(16),
    status              VARCHAR(16) DEFAULT 'active',
    created_date        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_date        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Medication Rights (9 Rights)
CREATE TABLE IF NOT EXISTS ni_pharm.medication_rights (
    right_code          VARCHAR(16) PRIMARY KEY,
    name                VARCHAR(128) NOT NULL,
    sequence            SMALLINT NOT NULL,
    framework           VARCHAR(32) DEFAULT 'WHO',
    description         TEXT,
    verification_checklist JSONB DEFAULT '[]',
    related_ipsg_goal_code VARCHAR(16),
    created_date        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Lab Reference Values
CREATE TABLE IF NOT EXISTS ni_pharm.lab_reference_values (
    lab_code            VARCHAR(32) PRIMARY KEY,
    name                VARCHAR(128) NOT NULL,
    name_pt             VARCHAR(128),
    loinc_code          VARCHAR(16),
    unit                VARCHAR(32),
    reference_low       NUMERIC,
    reference_high      NUMERIC,
    context             VARCHAR(64),
    created_date        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_lab_loinc ON ni_pharm.lab_reference_values(loinc_code);


-- ═══════════════════════════════════════════════════════════════════════════
-- KNOWLEDGE GRAPH (ni_graph schema)
-- ═══════════════════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS ni_graph.nodes (
    node_id             VARCHAR(64) PRIMARY KEY,
    node_type           VARCHAR(32) NOT NULL,
    entity_code         VARCHAR(64),
    label               VARCHAR(256),
    properties          JSONB DEFAULT '{}',
    embedding           vector(1536),
    status              VARCHAR(16) DEFAULT 'active',
    created_date        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_date        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_graph_node_type ON ni_graph.nodes(node_type);
CREATE INDEX idx_graph_node_entity ON ni_graph.nodes(entity_code);

CREATE TABLE IF NOT EXISTS ni_graph.edges (
    edge_id             UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    from_node           VARCHAR(64) NOT NULL REFERENCES ni_graph.nodes(node_id) ON DELETE CASCADE,
    to_node             VARCHAR(64) NOT NULL REFERENCES ni_graph.nodes(node_id) ON DELETE CASCADE,
    relation_type       VARCHAR(32) NOT NULL,
    weight              NUMERIC DEFAULT 1.0 CHECK (weight >= 0 AND weight <= 1),
    evidence_grade      VARCHAR(2) CHECK (evidence_grade IN ('A','B','C','D') OR evidence_grade IS NULL),
    rule_id             VARCHAR(64),
    status              VARCHAR(16) DEFAULT 'active',
    created_date        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_graph_edge_from ON ni_graph.edges(from_node);
CREATE INDEX idx_graph_edge_to ON ni_graph.edges(to_node);
CREATE INDEX idx_graph_edge_type ON ni_graph.edges(relation_type);


