-- Institutional Protocols (20 records)
ON CONFLICT (protocol_code) DO NOTHING;

-- Calculator Definitions (100 records)
ON CONFLICT (definition_code) DO NOTHING;

-- Graph Nodes: NANDA diagnoses
SELECT nanda_code, 'diagnosis', diagnosis_code, name_pt,
       jsonb_build_object('domain', domain_code, 'class', class_code, 'evidence', evidence_code)
FROM ni_clinical.nanda_diagnoses WHERE status = 'active'
ON CONFLICT (node_id) DO NOTHING;

-- Graph Nodes: NIC interventions
SELECT nic_code, 'intervention', intervention_code, name_pt,
       jsonb_build_object('domain', domain, 'activities_count', jsonb_array_length(activities))
FROM ni_clinical.nic_interventions WHERE status = 'active'
ON CONFLICT (node_id) DO NOTHING;

-- Graph Edges: NNN linkages
SELECT l.diagnosis_code, l.intervention_code, 'treats',
       CASE l.strength WHEN 'strong' THEN 0.9 WHEN 'moderate' THEN 0.6 ELSE 0.3 END,
       NULL, l.status
FROM ni_clinical.nnn_linkages l
WHERE l.status = 'active'
ON CONFLICT DO NOTHING;


