-- UPDATED_AT TRIGGER (auto-update updated_date)
-- ═══════════════════════════════════════════════════════════════════════════
CREATE OR REPLACE FUNCTION public.set_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_date = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Apply to all tables with updated_date
DO $$
DECLARE t RECORD;
BEGIN
    FOR t IN
        SELECT table_schema, table_name
        FROM information_schema.tables
        WHERE table_schema LIKE 'ni%'
          AND table_type = 'BASE TABLE'
          AND EXISTS (
              SELECT 1 FROM information_schema.columns
              WHERE table_schema = t.table_schema
                AND table_name = t.table_name
                AND column_name = 'updated_date'
          )
    LOOP
        EXECUTE format(
            'CREATE TRIGGER set_updated_at BEFORE UPDATE ON %I.%I FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();',
            t.table_schema, t.table_name
        );
    END LOOP;
END;
$$;

