-- VECTOR INDEX (pgvector) for semantic search
-- ═══════════════════════════════════════════════════════════════════════════
CREATE INDEX IF NOT EXISTS idx_graph_nodes_embedding 
    ON ni_graph.nodes USING ivfflat (embedding vector_cosine_ops) WITH (lists = 100);

CREATE INDEX IF NOT EXISTS idx_memory_episodes_embedding 
    ON ni_memory.episodes USING ivfflat (embedding vector_cosine_ops) WITH (lists = 100);

